-- Create "purchase_receipts" table
CREATE TABLE "purchase_receipts" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "receipt_no" character varying NOT NULL,
  "supplier_name" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'DRAFT',
  "received_at" timestamptz NOT NULL,
  "posted_at" timestamptz NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "business_record_id" bigint NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "purchase_receipts_business_records_purchase_receipts" FOREIGN KEY ("business_record_id") REFERENCES "business_records" ("id") ON UPDATE NO ACTION ON DELETE SET NULL
);
-- Create index "purchasereceipt_business_record_id" to table: "purchase_receipts"
CREATE INDEX "purchasereceipt_business_record_id" ON "purchase_receipts" ("business_record_id");
-- Create index "purchasereceipt_receipt_no" to table: "purchase_receipts"
CREATE UNIQUE INDEX "purchasereceipt_receipt_no" ON "purchase_receipts" ("receipt_no");
-- Create index "purchasereceipt_received_at" to table: "purchase_receipts"
CREATE INDEX "purchasereceipt_received_at" ON "purchase_receipts" ("received_at");
-- Create index "purchasereceipt_status" to table: "purchase_receipts"
CREATE INDEX "purchasereceipt_status" ON "purchase_receipts" ("status");
-- Create index "purchasereceipt_supplier_name" to table: "purchase_receipts"
CREATE INDEX "purchasereceipt_supplier_name" ON "purchase_receipts" ("supplier_name");
-- Create "purchase_receipt_items" table
CREATE TABLE "purchase_receipt_items" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "lot_no" character varying NULL,
  "quantity" numeric(20,6) NOT NULL,
  "unit_price" numeric(20,6) NULL,
  "amount" numeric(20,6) NULL,
  "source_line_no" character varying NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "lot_id" bigint NULL,
  "material_id" bigint NOT NULL,
  "receipt_id" bigint NOT NULL,
  "unit_id" bigint NOT NULL,
  "warehouse_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "purchase_receipt_items_inventory_lots_purchase_receipt_items" FOREIGN KEY ("lot_id") REFERENCES "inventory_lots" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_receipt_items_materials_purchase_receipt_items" FOREIGN KEY ("material_id") REFERENCES "materials" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_receipt_items_purchase_receipts_items" FOREIGN KEY ("receipt_id") REFERENCES "purchase_receipts" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_receipt_items_units_purchase_receipt_items" FOREIGN KEY ("unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_receipt_items_warehouses_purchase_receipt_items" FOREIGN KEY ("warehouse_id") REFERENCES "warehouses" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_receipt_items_amount_non_negative" CHECK ((amount IS NULL) OR (amount >= (0)::numeric)),
  CONSTRAINT "purchase_receipt_items_quantity_positive" CHECK (quantity > (0)::numeric),
  CONSTRAINT "purchase_receipt_items_unit_price_non_negative" CHECK ((unit_price IS NULL) OR (unit_price >= (0)::numeric))
);
-- Create index "purchasereceiptitem_lot_id" to table: "purchase_receipt_items"
CREATE INDEX "purchasereceiptitem_lot_id" ON "purchase_receipt_items" ("lot_id");
-- Create index "purchasereceiptitem_material_id" to table: "purchase_receipt_items"
CREATE INDEX "purchasereceiptitem_material_id" ON "purchase_receipt_items" ("material_id");
-- Create index "purchasereceiptitem_receipt_id" to table: "purchase_receipt_items"
CREATE INDEX "purchasereceiptitem_receipt_id" ON "purchase_receipt_items" ("receipt_id");
-- Create index "purchasereceiptitem_receipt_id_source_line_no" to table: "purchase_receipt_items"
CREATE UNIQUE INDEX "purchasereceiptitem_receipt_id_source_line_no" ON "purchase_receipt_items" ("receipt_id", "source_line_no") WHERE ((source_line_no IS NOT NULL) AND ((source_line_no)::text <> ''::text));
-- Create index "purchasereceiptitem_warehouse_id" to table: "purchase_receipt_items"
CREATE INDEX "purchasereceiptitem_warehouse_id" ON "purchase_receipt_items" ("warehouse_id");
